def validate_table_name(table_name: str) -> str:
    """Validate table name against whitelist."""
    if not table_name:
        raise ValueError("Table name cannot be empty.")

    # Strict validation: only allow alphanumeric and underscores
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', table_name):
        raise ValueError(f"Invalid table name format: '{table_name}'")

    table_name_lower = table_name.lower()
    if table_name_lower not in ALLOWED_TABLES:
        raise ValueError(
            f"Table '{table_name}' is not in the allowed tables list. "
            f"Allowed tables: {', '.join(sorted(ALLOWED_TABLES))}"
        )

    return table_name_lower


def validate_file_path(file_path: str) -> str:
    """
    Validate and sanitize the file path to prevent path traversal attacks.
    Returns the resolved, validated absolute path.
    """
    if not file_path:
        raise ValueError("File path cannot be empty.")

    # Resolve the path to eliminate ../, symlinks, etc.
    resolved_path = Path(file_path).resolve()
    allowed_base = Path(ALLOWED_BASE_DIRECTORY).resolve()

    # Check that the resolved path is under the allowed base directory
    try:
        resolved_path.relative_to(allowed_base)
    except ValueError:
        raise ValueError(
            f"File path must be within the allowed directory: {ALLOWED_BASE_DIRECTORY}. "
            f"Resolved path '{resolved_path}' is outside the allowed directory."
        )

    # Check file exists and is a regular file (not a symlink to outside, directory, etc.)
    if not resolved_path.exists():
        raise FileNotFoundError(f"File does not exist: {resolved_path}")

    if not resolved_path.is_file():
        raise ValueError(f"Path is not a regular file: {resolved_path}")

    # Check it's not a symlink pointing outside allowed directory
    if resolved_path.is_symlink():
        real_target = Path(os.path.realpath(str(resolved_path)))
        try:
            real_target.relative_to(allowed_base)
        except ValueError:
            raise ValueError(
                f"Symlink target is outside allowed directory: {real_target}"
            )

    # Check file extension
    suffix = resolved_path.suffix.lower()
    if suffix not in ALLOWED_EXTENSIONS:
        raise ValueError(
            f"File extension '{suffix}' is not allowed. "
            f"Allowed extensions: {', '.join(sorted(ALLOWED_EXTENSIONS))}"
        )

    # Check file size
    file_size = resolved_path.stat().st_size
    if file_size > MAX_FILE_SIZE_BYTES:
        raise ValueError(
            f"File size ({file_size} bytes) exceeds maximum allowed size "
            f"({MAX_FILE_SIZE_BYTES} bytes)."
        )

    if file_size == 0:
        raise ValueError("File is empty.")

    return str(resolved_path)


def get_db_connection(config: dict) -> mysql.connector.MySQLConnection:
    """Create a MySQL connection with local_infile enabled."""
    connection = mysql.connector.connect(
        host=config.get('host', 'localhost'),
        port=config.get('port', 3306),
        user=config['user'],
        password=config['password'],
        database=config['database'],
        allow_local_infile=True,
        connection_timeout=30,
        use_pure=True,
    )
    return connection


def build_load_data_query(table_name: str, file_path: str) -> tuple:
    """
    Build a parameterized LOAD DATA LOCAL INFILE query.
    Uses whitelisted table names and pre-defined schemas to avoid injection.
    Returns the query string (constructed safely from validated/whitelisted values).
    """
    # table_name is already validated against whitelist
    schema = TABLE_SCHEMAS.get(table_name)
    if not schema:
        raise ValueError(f"No schema definition found for table: {table_name}")

    # All values used in the query come from our hardcoded schema definitions,
    # not from user input. The file_path is validated and the table_name is whitelisted.
    # We use LOAD DATA LOCAL INFILE which reads from the client side.
    query = (
        f"LOAD DATA LOCAL INFILE %s "
        f"INTO TABLE `{table_name}` "
        f"FIELDS TERMINATED BY '{schema['fields_terminated_by']}' "
        f"ENCLOSED BY '{schema['enclosed_by']}' "
        f"LINES TERMINATED BY '{schema['lines_terminated_by']}' "
        f"IGNORE {schema['ignore_rows']} ROWS "
        f"{schema['columns']}"
    )

    return query, (file_path,)


def execute_bulk_import(config: dict, table_name: str, file_path: str) -> dict:
    """Execute the LOAD DATA LOCAL INFILE import."""
    # Validate inputs
    validated_table = validate_table_name(table_name)
    validated_path = validate_file_path(file_path)

    logger.info(f"Starting bulk import: file='{validated_path}' -> table='{validated_table}'")

    connection = None
    cursor = None
    result = {
        'success': False,
        'table': validated_table,
        'file': validated_path,
        'rows_affected': 0,
        'warnings': 0,
        'error': None,
    }

    try:
        connection = get_db_connection(config)
        cursor = connection.cursor()

        # Verify local_infile is enabled on the server
        cursor.execute("SHOW VARIABLES LIKE 'local_infile'")
        row = cursor.fetchone()
        if row is None or row[1].upper() != 'ON':
            raise RuntimeError(
                "MySQL server does not have local_infile enabled. "
                "Set 'local_infile=1' in MySQL server configuration."
            )

        # Build and execute the query
        query, params = build_load_data_query(validated_table, validated_path)

        logger.info(f"Executing LOAD DATA LOCAL INFILE for table '{validated_table}'")
        cursor.execute(query, params)

        result['rows_affected'] = cursor.rowcount
        result['warnings'] = cursor.warning_count

        # Check for warnings
        if cursor.warning_count > 0:
            cursor.execute("SHOW WARNINGS")
            warnings = cursor.fetchall()
            logger.warning(f"Import warnings: {warnings}")
            result['warning_details'] = warnings

        connection.commit()
        result['success'] = True
        logger.info(
            f"Bulk import completed successfully. "
            f"Rows affected: {result['rows_affected']}, Warnings: {result['warnings']}"
        )

    except mysql.connector.Error as e:
        if connection:
            connection.rollback()
        result['error'] = str(e)
        logger.error(f"MySQL error during bulk import: {e}")
        raise

    except Exception as e:
        if connection:
            connection.rollback()
        result['error'] = str(e)
        logger.error(f"Error during bulk import: {e}")
        raise

    finally:
        if cursor:
            cursor.close()
        if connection and connection.is_connected():
            connection.close()
            logger.info("Database connection closed.")

    return result


